mapper.select:
SELECT cert.id, cert.owner_id, o.owner_name, cert.house_id, c.community_name, bd.building_name, u.unit_name, h.house_code, cert.cert_status, cert.apply_time, cert.approve_time, cert.approver_id, cert.reject_reason FROM ow_certification cert LEFT JOIN ow_owner o ON cert.owner_id = o.id LEFT JOIN bs_house h ON cert.house_id = h.id LEFT JOIN bs_unit u ON h.unit_id = u.id LEFT JOIN bs_building bd ON u.building_id = bd.id LEFT JOIN bs_community c ON bd.community_id = c.id WHERE cert.del_flag = 0
AND cert.cert_status = #{query.certStatus}
AND c.id = #{query.communityId}
AND bd.id = #{query.buildingId}
ORDER BY cert.apply_time DESC
